\section{Method}
In this section, we first outline the fundamental principles and training paradigm of flow-based GRPO. Then, we revisit the reward evaluation mechanism within the standard GRPO, analyzing its limitations and highlighting the potential benefits of joint multi-condition assessment. Subsequently, we elaborate on the proposed MV-GRPO framework, which facilitates a comprehensive evaluation by leveraging an efficient online/offline Condition Enhancer.
\subsection{Preliminary}
\textbf{Flow Matching as MDP}.
Flow-based GRPO [] formulates the generation process as a multi-step Markov Decision Process (MDP).
% Given a condition $\mathbf{c}\in\mathcal{C}$ (e.g., a text prompt), the agent $p_\theta$ produces a reverse-time trajectory $\Gamma = (\mathbf{s}_T, \mathbf{a}_T, \dots, \mathbf{s}_0, \mathbf{a}_0)$, where the state at timestep $t$ is $\mathbf{s}_t = (\mathbf{c}, t, \mathbf{x}_t)$ and $\mathbf{x}_t$ denotes the noisy sample. Starting from $\mathbf{x}_T \sim \mathcal{N}(0, I)$, the process aims to reach the clean image $\mathbf{x}_0$. The action $\mathbf{a}_t$ stands for the single-step denoising update governed by the policy $\pi_\theta(\mathbf{x}_{t-1} | \mathbf{x}_t, \mathbf{c})$.
Let $\mathbf{c} \in \mathcal{C}$ be the condition. The agent $p_\theta$, parameterized by $\theta$, facilitates a reverse-time generation trajectory $\Gamma = (\mathbf{s}_T, \mathbf{a}_T, \dots, \mathbf{s}_0, \mathbf{a}_0)$. Here, the state $\mathbf{s}_t = (\mathbf{c}, t, \mathbf{x}_t)$ encompasses the current noisy latent $\mathbf{x}_t$ at timestep $t$, initializing from $\mathbf{x}_T \sim \mathcal{N}(0, I)$ and terminating at the clean sample $\mathbf{x}_0$. The action $\mathbf{a}_t$ corresponds to the single-step denoising update derived from the policy $\pi_\theta(\mathbf{x}_{t-1} | \mathbf{x}_t, \mathbf{c})$.
\noindent\textbf{Sampling with SDE}.
% While flow matching [] utilizes a deterministic Ordinary Differential Equation (ODE) for sampling,
% GRPO requires stochasticity to generate a diverse group of samples for advantage estimation.
% The Stochastic Differential Equation (SDE) [] is adopted at each timestep
% to inject randomness while maintaining the marginal probability flow, in which the sampling dynamics are governed by:
% \begin{equation}
%     d\mathbf{x}_t = \left(\boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c}) + \frac{\sigma_t^2}{2t}\Big(\mathbf{x}_t + (1-t)\boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c})\Big)\right)dt + \sigma_t d\mathbf{w}_t,
%     \label{eq:sde_sampling}
% \end{equation}
% where $\boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c})$ is the velocity field predicted by the model, and $\sigma_t$ controls the noise level injected via the Wiener process $d\mathbf{w}_t$.
Standard flow matching models [] typically utilize a deterministic Ordinary Differential Equation (ODE) for sampling:
\begin{equation}
    d\mathbf{x}_t = \boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c})dt,
    \label{eq:ode}
\end{equation}
where $\boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c})$ is the predicted flow velocity. To satisfy the stochastic exploration requirements of GRPO, prior works [] substitute the ODE with a Stochastic Differential Equation (SDE) that preserves the marginal distribution:
\begin{equation}
    d\mathbf{x}_t = \left(\boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c}) + \frac{\sigma_t^2}{2t}(\mathbf{x}_t + (1-t)\boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c}))\right)dt + \sigma_t d\mathbf{w}_t,
    \label{eq:sde}
\end{equation}
% where $d\mathbf{w}_t$ denotes the Wiener process increments and $\sigma_t = \eta \sqrt{\frac{t}{1-t}}$ controls the injected stochasticity governed by the hyperparameter $\eta$.
where $d\mathbf{w}_t$ represents the Wiener process increments. The term $\sigma_t = \eta \sqrt{\frac{t}{1-t}}$ modulates the magnitude of injected noise, governed by the hyperparameter $\eta$.
For practical implementation, this is discretized via the Euler-Maruyama scheme:
\begin{equation}
    \mathbf{x}_{t+\Delta t} = \mathbf{x}_t + \left(\boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c}) + \frac{\sigma_t^2}{2t}(\mathbf{x}_t + (1-t)\boldsymbol{v}_\theta(\mathbf{x}_t, t, \mathbf{c}))\right)\Delta t + \sigma_t \sqrt{\Delta t} \boldsymbol{\epsilon}, \quad \boldsymbol{\epsilon} \sim \mathcal{N}(0, I).
    \label{eq:discretization}
\end{equation}
\noindent\textbf{Training of GRPO}. For a given condition $\mathbf{c}$, a group of $G$ outputs $\{\mathbf{x}_0^i\}_{i=1}^G$ is generated via the SDE solver. Then, each sample is evaluated by a reward model $R(\mathbf{x}_0^i, \mathbf{c})$, under the same condition $\mathbf{c}$. These reward scores are further standardized against the group statistics to obtain the advantage $A_i$:
\begin{equation}
    A_i = \frac{R(\mathbf{x}_0^i, \mathbf{c}) - \text{mean}(\{R(\mathbf{x}_0^j, \mathbf{c})\}_{j=1}^G)}{\text{std}(\{R(\mathbf{x}_0^j, \mathbf{c})\}_{j=1}^G)}.
    \label{eq:advantage}
\end{equation}
The objective is to maximize the PPO-style surrogate gain constrained by a KL divergence term:
\begin{equation}
    \mathcal{J}(\theta) = \mathbb{E}_{\mathbf{c} \sim \mathcal{C}, \{\mathbf{x}^i\} \sim \pi_{\theta_{\text{old}}}(\cdot|\mathbf{c})} \left[ \frac{1}{G} \sum_{i=1}^G \frac{1}{T} \sum_{t=0}^{T-1} \mathcal{L}_{\text{clip}}(r_t^i, A_i) - \beta D_{\text{KL}}(\pi_\theta \| \pi_{\text{ref}}) \right],
    \label{eq:objective}
\end{equation}
where:
\begin{equation}
     \mathcal{L}_{\text{clip}}(r_t^i, A_i) = \min \left( r_t^i(\theta)A_i, \text{clip}(r_t^i(\theta), 1-\varepsilon, 1+\varepsilon)A_i \right),
    \label{eq:loss_function}
\end{equation}
\begin{equation}
r_t^i(\theta) = \frac{p_\theta(\mathbf{x}_{t-1}^i | \mathbf{x}_t^i, \mathbf{c})}{p_{\theta_{\text{old}}}(\mathbf{x}_{t-1}^i | \mathbf{x}_t^i, \mathbf{c})}.
\label{eq:ratio}
\end{equation}
The coefficient $\beta$ in Eq.~\ref{eq:objective} balances the KL regularization, which is typically set to 0 [] for stability in training.
\subsection{Reinterpretation of Reward Evaluation in GRPO}
% Prior to introducing MV-GRPO, we reinterpret the reward evaluation in standard GRPO methods as a "Single-View"
Prior to introducing MV-GRPO, we reinterpret the reward evaluation in standard flow-based GRPO as a "Single-View" paradigm, which motivates our method. As defined in Eq.~\ref{eq:advantage}, the policy update relies entirely on the relative advantage $A_i$, which is derived from a single condition $\mathbf{c}$. We argue that such evaluation protocol yields a \textbf{high-variance estimator} of the true sample quality.
\noindent\textbf{Observation}. Our premise stems from a critical observation: the reward ranking within a generated group is highly sensitive to the input condition. As illustrated in Fig. [], slight perturbations to $\mathbf{c}$ (e.g., synonymous rewriting) frequently trigger substantial shifts in the relative ordering of $\{\mathbf{x}_0^i\}_{i=1}^G$, while the images themselves remain static. This implies that a sample $\mathbf{x}_0^i$ might be deemed "positive" ($A_i > 0$) under view $\mathbf{c}$ but "negative" ($A_i < 0$) under a semantically similar view $\mathbf{c}'$.
% , leading to conflicting gradient signals during training.
\noindent\textbf{Information Asymmetry in Reward Evaluation}. We attribute this instability to the inherent information asymmetry between the sparse condition space $\mathcal{C}$ and the dense data space $\mathcal{X}$.
% A text prompt $\mathbf{c}\in\mathcal{C}$ is typically under-specified, covering only a fraction of the semantic details present in a high-fidelity image $\mathbf{x}\in\mathcal{X}$. For example,
A concise text condition $\mathbf{c}$ (e.g., "a dog") is usually \textit{under-specified}, corresponding to a vast manifold of valid images in $\mathcal{X}$. Conversely, a synthesized high-fidelity image $\mathbf{x}$ embodies dense semantic details (e.g., breed, pose, lighting, background) that far exceed the information content of $\mathbf{c}$.
% Mathematically, deriving the reward $R(\mathbf{x}_0^i, \mathbf{c})$ conditioned strictly on the initial prompt $\mathbf{c}$ implicitly models the valid condition distribution for the generated sample $\mathbf{x}_0^i$ as a Dirac delta function $\delta(\cdot - \mathbf{c})$. However, the condition space $\mathcal{C}$ forms a high-dimensional continuous manifold. A generated image $\mathbf{x}_0^i$ is valid not only for $\mathbf{c}$ but for a cluster of semantically adjacent descriptors. Let $\mathcal{N}_\epsilon(\mathbf{c}) = \{ \mathbf{c}' \in \mathcal{C} \mid d(\mathbf{c}, \mathbf{c}') < \epsilon \}$ denote the semantic neighborhood around the anchor $\mathbf{c}$, where $d(\cdot, \cdot)$ is a distance metric. The rigidity of the Dirac assumption ignores this local structure, making the evaluation \textbf{brittle}: strictly enforcing alignment to a single point $\mathbf{c}$ penalizes valid variations that drift slightly in the embedding space but remain within $\mathcal{N}_\epsilon(\mathbf{c})$.
Mathematically, the standard flow-based GRPO implicitly assumes that the feasible condition set $\mathcal{C}_{\mathbf{x}}$ for a generated sample $\mathbf{x}$ collapses to a singleton:
\begin{equation}
    \mathcal{C}_{\mathbf{x}} = \{ \mathbf{c} \}.
    \label{eq:singleton_set}
\end{equation}
However, the condition space $\mathcal{C}$ forms a high-dimensional continuous manifold. A generated image $\mathbf{x}$ is valid not only for $\mathbf{c}$ but for a cluster of semantically adjacent descriptors.
Let $\epsilon$ be a tolerance threshold and $d(\cdot, \cdot)$ is a semantic distance metric. The true feasible condition set for $\mathbf{x}$ can be modeled as the semantic neighborhood around the anchor $\mathbf{c}$:
% Let $\mathcal{N}_\epsilon(\mathbf{c}) = \{ \mathbf{c}' \in \mathcal{C} \mid d(\mathbf{c}, \mathbf{c}') < \epsilon \}$ denote the semantic neighborhood around the anchor $\mathbf{c}$, where $d(\cdot, \cdot)$ is a distance metric. The true feasible set should be modeled as the intersection of this neighborhood and the image's semantic projection:
\begin{equation}
    \mathcal{C}_{\mathbf{x}}^{\epsilon} \approx \{ \mathbf{c}' \in \mathcal{C} \mid d(\mathbf{c}, \mathbf{c}') < \epsilon \},
    \label{eq:neighborhood_set}
\end{equation}
The rigidity of the singleton assumption in Eq.~\ref{eq:singleton_set} ignores this local structure, making the evaluation \textbf{brittle}: strictly enforcing alignment to a single point $\mathbf{c}$ penalizes valid variations that drift slightly in the embedding space but remain within the valid manifold $\mathcal{C}_{\mathbf{x}}^{\epsilon}$.
\noindent\textbf{Motivation for Multi-View Evaluation}. To mitigate the estimation bias caused by the singleton assumption, we posit that the alignment quality should be assessed against a discrete approximation of the feasible manifold $\mathcal{C}_{\mathbf{x}}^{\epsilon}$.
Instead of relying on a solitary anchor $\mathbf{c}$, we propose to construct an \textit{Augmented Condition Set} $\mathcal{V}_K$ by sampling $K$ auxiliary views from the semantic neighborhood:
\begin{equation}
    \mathcal{V}_K = \{ \mathbf{c} \} \cup \{ \mathbf{c}_k \}_{k=1}^K, \quad \text{where } \mathbf{c}_k \in \mathcal{C}_{\mathbf{x}}^{\epsilon}.
    \label{eq:view_set}
\end{equation}
Under this paradigm, the evaluation protocol shifts from a sparse point-check to a \textbf{Dense Multi-View Mapping}. Specifically, the scalar reward function is expanded into a vector-valued function $\Phi: \mathcal{X} \rightarrow \mathbb{R}^{K+1}$, capturing the alignment level across the entire condition cluster:
\begin{equation}
    \Phi(\mathbf{x}) = \mathbf{R}(\mathbf{x}, \mathcal{V}_K) = \left[ R(\mathbf{x}, \mathbf{c}), R(\mathbf{x}, \mathbf{c}_1), \dots, R(\mathbf{x}, \mathbf{c}_K) \right]^\top.
    \label{eq:dense_mapping}
\end{equation}
By leveraging the joint information embedded in $\Phi(\mathbf{x})$, we can derive a consensus-based evaluation that is robust to individual view noise and representative of the intrinsic sample quality. This theoretical formulation lays the groundwork for our MV-GRPO framework, where we instantiate the construction of $\mathcal{V}_K$ via pretrained Condition Enhancers.
\subsection{Multi-View GRPO}
Building upon the above motivation of dense mapping, we propose MV-GRPO, a multi-view RL framework  designed to maximize alignment stability and sample utility in GRPO training. As shown in Fig. [], MV-GRPO instantiates the augmented condition set $\mathcal{V}_K$ through a plug-and-play \textbf{Condition Enhancer} module and optimizes the policy using these augmented sample groups.
\noindent \textbf{Condition Enhancer}. We introduce a Condition Enhancer $\mathcal{E}$ that generates auxiliary views. Here, we propose two complementary implementations of $\mathcal{E}$:
\begin{enumerate}
    \item \textbf{Posterior Augmentation via Online VLM}.
    To capture the intrinsic visual semantics of the generated samples, we employ a pretrained Vision-Language Model (VLM) as an online Condition Enhancer in the training loop. For a group $G$ of generated samples $\{\mathbf{x}_0^i\}_{i=1}^G$, the VLM projects each image back to the condition space $\mathcal{C}$ to obtain its posterior descriptor:
    \begin{equation}\label{eq:projection}
        \mathbf{c}_i^{\text{post}} \sim p_{\text{VLM}}(\cdot | \mathbf{x}_0^i, \texttt{P}), \quad \forall i \in \{1, \dots, G\},
    \end{equation}
    where the prompt $\texttt{P}$ instructs the VLM to describe visual contents within the sample $\mathbf{x}_0^i$. Specifically, for each projection operation in Eq.~\ref{eq:projection}, $\texttt{P}$ is randomly sampled from a diverse instruction set $\mathcal{P}$ covering multiple descriptive perspectives (e.g., \texttt{lighting}, \texttt{composition}, \texttt{style}, etc.). This design guarantees the diversity of the augmented conditions from two distinct dimensions: (i) First, each $\mathbf{c}_i^{\text{post}}$ is derived from a unique SDE sample $\mathbf{x}_0^i$; (ii) Second, the VLM is queried with varied instructions $\texttt{P}$ focusing on different attributes.
    % These generated descriptors collectively form the posterior condition set $\mathcal{C}_{\text{post}} = \{ \mathbf{c}_i^{\text{post}} \}_{i=1}^G$.
    Since the VLM grounds the alignment process in the actual visual samples produced by the model, these posterior descriptors $\{ \mathbf{c}_i^{\text{post}} \}_{i=1}^G$ dynamically reflect the model's current generation capability, thereby providing a more precise and adaptive supervision signal.
    \item \textbf{Prior Augmentation via Offline LLM}. Complementary to the posterior offered by VLM , the Condition Enhancer can also be implemented as a Large Language Model (LLM), which efficiently explores the condition manifold in a prior manner. Given the anchor condition $\mathbf{c}$, the LLM directly samples a set of $G$ semantically similar variations on the condition space $\mathcal{C}$:
    \begin{equation}
        \mathbf{c}_i^{\text{prior}} \sim p_{\text{LLM}}(\cdot | \mathbf{c}, \texttt{Mem}, \texttt{P}^{'}), \quad \forall i \in \{1, \dots, G\},
    \end{equation}
    where the prompt $\texttt{P}'$ denotes the rewriting instruction, and $\texttt{Mem}$ represents a historical output buffer introduced to prevent duplicate outputs.
    Mirroring the VLM strategy, $\texttt{P}'$ is also sampled from a pre-defined editing prompt set $\mathcal{P}'$, which encompasses three perturbation operations: \texttt{addition}, \texttt{deletion}, and \texttt{substitution}. These mechanisms ensures unique and diverse variations within the prior condition cluster $\{\mathbf{c}_i^{\text{prior}}\}_{i=1}^G$.
    Crucially, since this augmentation operates independently of image generation, it can be executed entirely offline before training, incurring no extra overhead during the RL loop.
    % This strategy incurs zero computational overhead during the online RL loop, maximizing training throughput while effectively densifying the condition space with linguistic diversity.
\end{enumerate}
